  awk '
    /^[a-z0-9_]+_(render|info|validate)[[:space:]]*\(\)[[:space:]]*\{/ { fn=$1; sub(/\(\).*/,"",fn); body=""; inb=1; next }
    inb {
      body=body"\n"$0
      if ($0 ~ /^\}/) {
